const items = $input.all();
const classData = $('Parse Klassifikation').first().json;
const extractData = $('Firma extrahieren').first().json;
let csReport = {};
try { csReport = $('Creditsafe Bericht').first().json; } catch(e) {}

const results = [];

for (const item of items) {
  try {
    const content = item.json.content || '';
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      results.push({
        json: {
          firmenname: classData.firmenname,
          branche: classData.branche,
          extrahierte_daten: classData.extrahierte_daten,
          original_email: classData.original_email,
          company_id: extractData.company_id,
          company_found: extractData.company_found,
          creditsafe_error: extractData.creditsafe_error,
          ampel: parsed.ampel,
          score: parsed.score,
          ampel_begruendung: parsed.begruendung,
          risikofaktoren: parsed.risikofaktoren,
          empfehlung: parsed.empfehlung,
          creditsafe_raw: csReport
        }
      });
    } else {
      results.push({
        json: {
          firmenname: classData.firmenname,
          branche: classData.branche,
          extrahierte_daten: classData.extrahierte_daten,
          original_email: classData.original_email,
          ampel: 'GELB',
          score: 0,
          ampel_begruendung: 'GPT-Antwort konnte nicht geparst werden',
          risikofaktoren: ['Parse-Fehler'],
          empfehlung: 'Manuelle Bonitätsprüfung durchführen'
        }
      });
    }
  } catch (e) {
    results.push({
      json: {
        firmenname: classData.firmenname,
        branche: classData.branche,
        extrahierte_daten: classData.extrahierte_daten,
        original_email: classData.original_email,
        ampel: 'GELB',
        score: 0,
        ampel_begruendung: 'Fehler: ' + e.message,
        risikofaktoren: ['Verarbeitungsfehler'],
        empfehlung: 'Manuelle Bonitätsprüfung durchführen'
      }
    });
  }
}

return results;
